-- ── Postorius ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Postorius is the free, open-source Django-based web interface for administering and using GNU Mailman 3 mailing lists, covering list creation, subscription management, and moderation.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (volunteer-run open-source project, not a company)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (distributed open-source project maintained by the GNU Mailman core team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Postorius Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Postorius review: the free open-source web UI for GNU Mailman 3 mailing lists. List admin features, setup basics, and alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Postorius is the official web-based administrative and user interface for GNU Mailman 3, the open-source mailing list manager maintained by the GNU Project and the Mailman core development team. Built as a Django web application, Postorius originated as a Google Summer of Code project in 2010 and 2011, developed initially by contributors Anna Senarclens de Grancy and Benedict Stein, and has since been maintained by the broader Mailman open-source community rather than by a commercial company. It works alongside Mailman Core (the list-processing engine) and HyperKitty (the web-based archive viewer) as one of three components in the modern Mailman 3 suite, communicating with Mailman Core over its REST API. Postorius lets list owners create and configure mailing lists, manage subscriptions and unsubscriptions, set moderation and posting policies, manage bounce processing, and customize list templates and headers and footers, while giving individual members a self-service interface to manage their own subscription settings, delivery preferences, and email addresses across multiple lists. Because it is entirely free and open source (distributed under the GNU General Public License and published on GitLab under the GNU Mailman organization), there is no pricing model, subscription tiers, or vendor lock-in -- organizations self-host it themselves, typically alongside Mailman Core on a Linux server, and it requires Python 3.9 or later and Django 4.2 or later to run. Postorius targets system administrators, open-source project maintainers, universities, and community organizations that run their own mailing lists and want a modern web UI instead of Mailman 2's older CGI-based admin pages or command-line list management. Because it is a self-hosted, non-commercial project, it does not have direct competitors in the SaaS sense, but organizations evaluating mailing list infrastructure often compare Mailman and Postorius against hosted list and newsletter tools such as Google Groups, Groups.io, and Listserv, or against self-hosted alternatives like Sympa, when deciding whether to run their own list server or use a managed service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6930e11f-db83-4fac-9da3-6754439654e5';

