INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$No published self-serve monthly pricing -- plans start at $499/month on an annual contract$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Entry-level Core plan lacks AI automation and supplier-portal features found in Automation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Enterprise-grade needs (unlimited users, full ERP integration) require custom Enterprise pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Primarily aimed at mid-market companies, so very small businesses may find it more than they need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$As with most procurement software, full ROI depends on disciplined internal adoption of approval workflows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$How much does Precoro cost?$q$, $q$Precoro's Core plan starts at $499/month billed annually, with Automation at $999/month and custom Enterprise pricing for larger organizations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$What does Precoro's Core plan include?$q$, $q$Purchase requisitions, orders, receipts, invoices, 2- and 3-way matching, approval workflows, catalogs, vendor management, and basic integrations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Does Precoro use AI?$q$, $q$Yes, its Automation and Enterprise plans include AI document scanning for invoices and an AI assistant.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Does Precoro integrate with accounting software?$q$, $q$Yes, it integrates with QuickBooks Online, Xero, and NetSuite, among others.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Who is Precoro built for?$q$, $q$Precoro is built for mid-sized companies that have outgrown manual or spreadsheet-based purchasing but don't need a full enterprise ERP procurement suite.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Is there a free trial for Precoro?$q$, $q$Yes, Precoro offers a free trial before committing to an annual contract.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Where is Precoro headquartered?$q$, $q$Precoro is headquartered in New York, with engineering teams in Kyiv, Ukraine and Vilnius, Lithuania.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$What are Precoro's main competitors?$q$, $q$Commonly cited alternatives include Coupa, Procurify, Zip, and SAP Ariba.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Purchase requisition and approval automation$q$, $q$A growing company replaces manual, email-based purchase requests with automated requisitions and approval routing.$q$, $q$Mid-market operations and finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Accounts payable automation$q$, $q$A finance team automates invoice capture, matching, and approval to reduce manual AP processing time.$q$, $q$Accounts payable and finance departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Multi-location vendor management$q$, $q$A retail or hospitality group centralizes vendor contracts, catalogs, and purchasing across multiple locations.$q$, $q$Multi-location retail, hospitality, and manufacturing companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Core$q$, $q$$499/month$q$, $q$billed annually$q$, NULL, $q$["Purchase requisitions, orders, receipts, and invoices","2- and 3-way matching","Custom approval workflows","Vendor management and contract repository","Basic integrations (QuickBooks Online, Xero, Slack)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Automation$q$, $q$$999/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Core","Intelligent AP automation and e-invoicing","AI document scanning and AI assistant","Supplier portal and PunchOut catalogs","Advanced integrations with API access and SSO"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$billed annually$q$, NULL, $q$["Everything in Automation","Unlimited users and advanced admin controls","ERP system integrations","Regional server selection (US or EU) and IP whitelisting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$AP Module$q$, $q$$499/month$q$, $q$billed annually$q$, NULL, $q$["Invoice processing and intelligent AP automation","E-invoicing","Budget management and AI expenses","Vendor management and payments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Precoro is cloud-based procurement and spend management software that automates the purchase-to-pay process -- requisitions, purchase orders, approvals, receiving, invoice matching, and accounts payable -- for mid-sized organizations moving off spreadsheets or manual processes.$q$, $q$Founded in 2015 and headquartered in New York with engineering teams in Kyiv, Ukraine and Vilnius, Lithuania, Precoro positions itself as a bootstrapped, mid-market-focused alternative to larger enterprise procurement suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes purchase requisitions and orders, 2- and 3-way invoice matching, custom approval workflows, service and item catalogs, vendor and contract management, expense management, and budget tracking with reporting.$q$, $q$The Automation tier adds intelligent AP automation and e-invoicing, AI-powered document scanning for invoices, an AI assistant, PunchOut catalogs, a supplier portal for vendor onboarding, intake management, and real-time budget tracking, alongside advanced integrations and SSO.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1b529879-d2eb-436f-9583-eb2ecac8f8c7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Precoro is sold as an annual-contract subscription rather than self-serve monthly pricing. The Core plan starts at $499/month (billed annually) for essential procurement workflows, and the Automation plan is $999/month, adding AP automation and AI features.$q$, $q$Enterprise pricing is custom-quoted for organizations needing unlimited users, ERP integrations, and regional data residency, and a standalone AP Module is also available starting at $499/month for companies that only need invoice and payables automation.$q$]::text[], 2);
